"use strict";

import React from 'react';
import PropTypes from 'prop-types';
import createReactClass from 'create-react-class';
import utils from '@openagenda/utils';
import suggestionLabels from '@openagenda/labels/agenda-locations/suggestion';
import formLabels from '@openagenda/labels/agenda-locations/form';
import get from '@openagenda/utils/get';
import Spinner from '@openagenda/react-form-components/build/Spinner';
import makeLabelGetter from '@openagenda/labels';
import LocationForm from './LocationForm';
import helpers from './suggestions.helpers';

var getLabel = makeLabelGetter( utils.extend( {}, formLabels, suggestionLabels ) );


/**
 * Suggestion form preloads a location form for a stakeholder
 * for him to suggest and submit changes to an agenda moderator
 *
 * propTypes include the stakeholder Id, the form then loads the location
 * with the relevent suggestion if already existing.
 *
 * It then proceeds to preload the suggestions in the location form
 */
module.exports = createReactClass( {

  displayName: 'SuggestionForm',

  propTypes: {

    lang: PropTypes.string.isRequired,

    locationUid: PropTypes.number,
    
    res: PropTypes.shape({
      getSuggestion: PropTypes.string,
      setSuggestion: PropTypes.string,
      reverseGeocode: PropTypes.string,
      geocode: PropTypes.string,
      image: PropTypes.shape( {
        upload: PropTypes.string,
        remove: PropTypes.string
      } )
    }).isRequired,

    redirects: PropTypes.shape( {
      cancel: PropTypes.string.isRequired,
      success: PropTypes.string.isRequired
    } ).isRequired

  },

  getInitialState() {

    return {
      loading: true,
      loadError: false,
      location: false,
      settings: false,
      completed: false
    }

  },

  componentWillMount() {

    log( 'componentWillMount' );

    get( this.props.res.getSuggestion.replace( ':locationUid', this.props.locationUid ), ( err, result ) => {

      if ( err ) {

        return this.setState( { loadError: true } );

      }

      this.setState( {
        loading: false,
        location: result.location,
        settings: result.settings
      } );

    } );

  },

  onCancel() {

    window.location.href = this.props.redirects.cancel

  },

  renderHeader() {

    if ( this.state.location.suggestions && this.state.location.suggestions.length ) {

      return <div className="form-head">
        <a onClick={ this.onCancel }>{ getLabel( 'back', this.props.lang ) }</a>
        <h2>{ getLabel( 'suggestionEditTitle', this.props.lang )}</h2>
        <span className="info">{ getLabel( 'suggestionEditInfo', this.props.lang ) }</span>
      </div>

    } else {

      return <div className="form-head">
        <a onClick={ this.onCancel }>{ getLabel( 'back', this.props.lang ) }</a>
        <h2>{ getLabel( 'title', this.props.lang ) }</h2>
        <span className="info">{ getLabel( 'info', this.props.lang ) }</span>
      </div>

    }

  },

  showComplete() {

    this.setState( {
      completed: true
    } );

  },

  renderCompleted() {

    return <div className="page-dialog">
      <div className="content jumbotron text-center">
        <p>{ getLabel( 'completeTitle', this.props.lang ) }</p>
      </div>
      <p className="content">{ getLabel( 'completeText', this.props.lang ) }</p>
      <div className="content actions text-center">
        <a onClick={ this.closeForm } className="btn btn-primary">{ getLabel( 'completeLink', this.props.lang )}</a>
      </div>
    </div>

  },

  closeForm() {

    window.location.href = this.props.redirects.success;

  },

  render() {

    if ( this.state.loading ) {

      return <Spinner/>;

    }

    if ( this.state.loadError ) {

      return <p>{suggestionLabels.loadError[ this.props.lang ]}</p>

    }

    if ( this.state.completed ) {

      return this.renderCompleted();

    }


    let alt = helpers.prepareAlternatives( this.state.location, this.props, suggestionLabels );

    return <LocationForm
      Header={ this.renderHeader() }
      lang={ this.props.lang }
      labels={ suggestionLabels }
      location={ alt.location }
      alternatives={ alt.alternatives }
      res={{
        set: this.props.res.setSuggestion.replace( ':locationUid', this.props.locationUid ),
        image: {
          upload: this.props.res.image.upload.replace( ':locationUid', this.props.locationUid ),
          remove: this.props.res.image.remove.replace( ':locationUid', this.props.locationUid )
        },
        reverseGeocode: this.props.res.reverseGeocode,
        geocode: this.props.res.geocode
      }}
      hideCurrentAlternative={ true }
      disableAutoTranslation={ true }
      detailedInfo={ this.state.settings.eventForm && this.state.settings.eventForm.detailed }
      settings={ this.state.settings }
      onCancel={ this.onCancel }
      onSuccess={ this.showComplete }
    />

  }

} );

function log() {

  console.log.apply( console, arguments );

}